// Combine completed and failed jobs, filter to those older than 24 hours
const completed = $('List Completed Jobs').item.json.jobs || [];
const failed = $('List Failed Jobs').item.json.jobs || [];
const allJobs = [...completed, ...failed];

const cutoff = Date.now() - (24 * 60 * 60 * 1000); // 24 hours ago
const oldJobs = allJobs.filter(job => {
  const created = new Date(job.created_at || job.completed_at || 0).getTime();
  return created < cutoff;
});

if (oldJobs.length === 0) {
  return [{ json: { action: 'none', message: 'No jobs older than 24 hours to clean up' } }];
}

return oldJobs.map(job => ({
  json: {
    job_id: job.job_id,
    status: job.status,
    created_at: job.created_at,
    filename: job.filename
  }
}));
